   200→		return ret, fmt.Errorf("+genclient=%s is invalid, use //+genclient if you want to generate client or omit it when you want to disable generation", value)
   201→	}
   202→	_, ret.NonNamespaced = values[genClientPrefix+"nonNamespaced"]
   203→	// Check the old format and error when used
   204→	if value := values["nonNamespaced"]; len(value) > 0 && len(value[0]) > 0 {
   205→		return ret, fmt.Errorf("+nonNamespaced=%s is invalid, use //+genclient:nonNamespaced instead", value[0])
   206→	}
   207→	_, ret.NoVerbs = values[genClientPrefix+"noVerbs"]
   208→	_, ret.NoStatus = values[genClientPrefix+"noStatus"]
   209→	onlyVerbs := []string{}
   210→	if _, isReadonly := values[genClientPrefix+"readonly"]; isReadonly {
   211→		onlyVerbs = ReadonlyVerbs
   212→	}
   213→	// Check the old format and error when used
   214→	if value := values["readonly"]; len(value) > 0 && len(value[0]) > 0 {
   215→		return ret, fmt.Errorf("+readonly=%s is invalid, use //+genclient:readonly instead", value[0])
   216→	}
   217→	if v, exists := values[genClientPrefix+"skipVerbs"]; exists {
   218→		ret.SkipVerbs = strings.Split(v[0], ",")
   219→	}
   220→	if v, exists := values[genClientPrefix+"onlyVerbs"]; exists || len(onlyVerbs) > 0 {
   221→		if len(v) > 0 {
   222→			onlyVerbs = append(onlyVerbs, strings.Split(v[0], ",")...)
   223→		}
   224→		skipVerbs := []string{}
   225→		for _, m := range SupportedVerbs {
   226→			skip := true
   227→			for _, o := range onlyVerbs {
   228→				if o == m {
   229→					skip = false
   230→					break
   231→				}
   232→			}
   233→			// Check for conflicts
   234→			for _, v := range skipVerbs {
   235→				if v == m {
   236→					return ret, fmt.Errorf("verb %q used both in genclient:skipVerbs and genclient:onlyVerbs", v)
   237→				}
   238→			}
   239→			if skip {
   240→				skipVerbs = append(skipVerbs, m)
   241→			}
   242→		}
   243→		ret.SkipVerbs = skipVerbs
   244→	}
   245→	var err error
   246→	if ret.Extensions, err = parseClientExtensions(values); err != nil {
   247→		return ret, err
   248→	}
   249→	return ret, validateClientGenTags(values)
   250→}
   251→
   252→func parseClientExtensions(tags map[string][]string) ([]extension, error) {
   253→	var ret []extension
   254→	for name, values := range tags {
   255→		if !strings.HasPrefix(name, genClientPrefix+"method") {
   256→			continue
   257→		}
   258→		for _, value := range values {
   259→			// the value comes in this form: "Foo,verb=create"
   260→			ext := extension{}
   261→			parts := strings.Split(value, ",")
   262→			if len(parts) == 0 {
   263→				return nil, fmt.Errorf("invalid of empty extension verb name: %q", value)
   264→			}
   265→			// The first part represents the name of the extension
   266→			ext.VerbName = parts[0]
   267→			if len(ext.VerbName) == 0 {
   268→				return nil, fmt.Errorf("must specify a verb name (// +genclient:method=Foo,verb=create)")
   269→			}
   270→			// Parse rest of the arguments
   271→			params := parts[1:]
   272→			for _, p := range params {
   273→				parts := strings.Split(p, "=")
   274→				if len(parts) != 2 {
   275→					return nil, fmt.Errorf("invalid extension tag specification %q", p)
   276→				}
   277→				key, val := strings.TrimSpace(parts[0]), strings.TrimSpace(parts[1])
   278→				if len(val) == 0 {
   279→					return nil, fmt.Errorf("empty value of %q for %q extension", key, ext.VerbName)
   280→				}
   281→				switch key {
   282→				case "verb":
   283→					ext.VerbType = val
   284→				case "subresource":
   285→					ext.SubResourcePath = val
   286→				case "input":
   287→					ext.InputTypeOverride = val
   288→				case "result":
   289→					ext.ResultTypeOverride = val
   290→				default:
   291→					return nil, fmt.Errorf("unknown extension configuration key %q", key)
   292→				}
   293→			}
   294→			// Validate resulting extension configuration
   295→			if len(ext.VerbType) == 0 {
   296→				return nil, fmt.Errorf("verb type must be specified (use '// +genclient:method=%s,verb=create')", ext.VerbName)
   297→			}
   298→			if len(ext.ResultTypeOverride) > 0 {
   299→				supported := false
   300→				for _, v := range resultTypeSupportedVerbs {
   301→					if ext.VerbType == v {
   302→						supported = true
   303→						break
   304→					}
   305→				}
   306→				if !supported {
   307→					return nil, fmt.Errorf("%s: result type is not supported for %q verbs (supported verbs: %#v)", ext.VerbName, ext.VerbType, resultTypeSupportedVerbs)
   308→				}
   309→			}
   310→			if len(ext.InputTypeOverride) > 0 {
   311→				supported := false
   312→				for _, v := range inputTypeSupportedVerbs {
   313→					if ext.VerbType == v {
   314→						supported = true
   315→						break
   316→					}
   317→				}
   318→				if !supported {
   319→					return nil, fmt.Errorf("%s: input type is not supported for %q verbs (supported verbs: %#v)", ext.VerbName, ext.VerbType, inputTypeSupportedVerbs)
   320→				}
   321→			}
   322→			for _, t := range unsupportedExtensionVerbs {
   323→				if ext.VerbType == t {
   324→					return nil, fmt.Errorf("verb %q is not supported by extension generator", ext.VerbType)
   325→				}
   326→			}
   327→			ret = append(ret, ext)
   328→		}
   329→	}
   330→	return ret, nil
   331→}
   332→
   333→// validateTags validates that only supported genclient tags were provided.
   334→func validateClientGenTags(values map[string][]string) error {
   335→	for _, k := range supportedTags {
   336→		delete(values, k)
   337→	}
   338→	for key := range values {
   339→		if strings.HasPrefix(key, strings.TrimSuffix(genClientPrefix, ":")) {
   340→			return errors.New("unknown tag detected: " + key)
   341→		}
   342→	}
   343→	return nil
   344→}
