   153→// Complete completes all the required options
   154→func (o *CanIOptions) Complete(f cmdutil.Factory, args []string) error {
   155→	// Set default WarningPrinter if not already set.
   156→	if o.WarningPrinter == nil {
   157→		o.WarningPrinter = printers.NewWarningPrinter(o.ErrOut, printers.WarningPrinterOptions{Color: term.AllowsColorOutput(o.ErrOut)})
   158→	}
   159→
   160→	if o.List {
   161→		if len(args) != 0 {
   162→			return errors.New("list option must be specified with no arguments")
   163→		}
   164→	} else {
   165→		if o.Quiet {
   166→			o.Out = io.Discard
   167→		}
   168→
   169→		switch len(args) {
   170→		case 2:
   171→			o.Verb = args[0]
   172→			if strings.HasPrefix(args[1], "/") {
   173→				o.NonResourceURL = args[1]
   174→				break
   175→			}
   176→			resourceTokens := strings.SplitN(args[1], "/", 2)
   177→			restMapper, err := f.ToRESTMapper()
   178→			if err != nil {
   179→				return err
   180→			}
   181→			o.Resource = o.resourceFor(restMapper, resourceTokens[0])
   182→			if len(resourceTokens) > 1 {
   183→				o.ResourceName = resourceTokens[1]
   184→			}
   185→		default:
   186→			errString := "you must specify two arguments: verb resource or verb resource/resourceName."
   187→			usageString := "See 'kubectl auth can-i -h' for help and examples."
   188→			return fmt.Errorf("%s\n%s", errString, usageString)
   189→		}
   190→	}
   191→
   192→	var err error
   193→	client, err := f.KubernetesClientSet()
   194→	if err != nil {
   195→		return err
   196→	}
   197→	o.AuthClient = client.AuthorizationV1()
   198→	o.DiscoveryClient = client.Discovery()
   199→	o.Namespace = ""
   200→	if !o.AllNamespaces {
   201→		o.Namespace, _, err = f.ToRawKubeConfigLoader().Namespace()
   202→		if err != nil {
   203→			return err
   204→		}
   205→	}
   206→
   207→	return nil
   208→}
