   210→// Validate makes sure provided values for CanIOptions are valid
   211→func (o *CanIOptions) Validate() error {
   212→	if o.List {
   213→		if o.Quiet || o.AllNamespaces || o.Subresource != "" {
   214→			return errors.New("list option can't be specified with neither quiet, all-namespaces nor subresource options")
   215→		}
   216→		return nil
   217→	}
   218→
   219→	if o.WarningPrinter == nil {
   220→		return fmt.Errorf("WarningPrinter can not be used without initialization")
   221→	}
   222→
   223→	if o.NonResourceURL != "" {
   224→		if o.Subresource != "" {
   225→			return fmt.Errorf("--subresource can not be used with NonResourceURL")
   226→		}
   227→		if o.Resource != (schema.GroupVersionResource{}) || o.ResourceName != "" {
   228→			return fmt.Errorf("NonResourceURL and ResourceName can not specified together")
   229→		}
   230→		if !isKnownNonResourceVerb(o.Verb) {
   231→			o.WarningPrinter.Print(fmt.Sprintf("verb '%s' is not a known verb\n", o.Verb))
   232→		}
   233→	} else if !o.Resource.Empty() && !o.AllNamespaces && o.DiscoveryClient != nil {
   234→		if namespaced, err := isNamespaced(o.Resource, o.DiscoveryClient); err == nil && !namespaced {
   235→			if len(o.Resource.Group) == 0 {
   236→				o.WarningPrinter.Print(fmt.Sprintf("resource '%s' is not namespace scoped\n", o.Resource.Resource))
   237→			} else {
   238→				o.WarningPrinter.Print(fmt.Sprintf("resource '%s' is not namespace scoped in group '%s'\n", o.Resource.Resource, o.Resource.Group))
   239→			}
   240→		}
   241→		if !isKnownResourceVerb(o.Verb) {
   242→			o.WarningPrinter.Print(fmt.Sprintf("verb '%s' is not a known verb\n", o.Verb))
   243→		}
   244→	}
   245→
   246→	if o.NoHeaders {
   247→		return fmt.Errorf("--no-headers cannot be set without --list specified")
   248→	}
   249→	return nil
   250→}
