   267→// RunAccessCheck checks if user has access to a certain resource or non resource URL
   268→func (o *CanIOptions) RunAccessCheck() (bool, error) {
   269→	var sar *authorizationv1.SelfSubjectAccessReview
   270→	if o.NonResourceURL == "" {
   271→		sar = &authorizationv1.SelfSubjectAccessReview{
   272→			Spec: authorizationv1.SelfSubjectAccessReviewSpec{
   273→				ResourceAttributes: &authorizationv1.ResourceAttributes{
   274→					Namespace:   o.Namespace,
   275→					Verb:        o.Verb,
   276→					Group:       o.Resource.Group,
   277→					Resource:    o.Resource.Resource,
   278→					Subresource: o.Subresource,
   279→					Name:        o.ResourceName,
   280→				},
   281→			},
   282→		}
   283→	} else {
   284→		sar = &authorizationv1.SelfSubjectAccessReview{
   285→			Spec: authorizationv1.SelfSubjectAccessReviewSpec{
   286→				NonResourceAttributes: &authorizationv1.NonResourceAttributes{
   287→					Verb: o.Verb,
   288→					Path: o.NonResourceURL,
   289→				},
   290→			},
   291→		}
   292→	}
   293→
   294→	response, err := o.AuthClient.SelfSubjectAccessReviews().Create(context.TODO(), sar, metav1.CreateOptions{})
   295→	if err != nil {
   296→		return false, err
   297→	}
   298→	if response.Status.Allowed {
   299→		fmt.Fprintln(o.Out, "yes")
   300→	} else {
   301→		fmt.Fprint(o.Out, "no")
   302→		if len(response.Status.Reason) > 0 {
   303→			fmt.Fprintf(o.Out, " - %v", response.Status.Reason)
   304→		}
   305→		if len(response.Status.EvaluationError) > 0 {
   306→			fmt.Fprintf(o.Out, " - %v", response.Status.EvaluationError)
   307→		}
   308→		fmt.Fprintln(o.Out)
   309→	}
   310→
   311→	return response.Status.Allowed, nil
