   314→func (o *CanIOptions) resourceFor(mapper meta.RESTMapper, resourceArg string) schema.GroupVersionResource {
   315→	if resourceArg == "*" {
   316→		return schema.GroupVersionResource{Resource: resourceArg}
   317→	}
   318→
   319→	fullySpecifiedGVR, groupResource := schema.ParseResourceArg(strings.ToLower(resourceArg))
   320→	gvr := schema.GroupVersionResource{}
   321→	if fullySpecifiedGVR != nil {
   322→		gvr, _ = mapper.ResourceFor(*fullySpecifiedGVR)
   323→	}
   324→	if gvr.Empty() {
   325→		var err error
   326→		gvr, err = mapper.ResourceFor(groupResource.WithVersion(""))
   327→		if err != nil {
   328→			if !nonStandardResourceNames.Has(groupResource.String()) {
   329→				if len(groupResource.Group) == 0 {
   330→					o.WarningPrinter.Print(fmt.Sprintf("the server doesn't have a resource type '%s'\n", groupResource.Resource))
   331→				} else {
   332→					o.WarningPrinter.Print(fmt.Sprintf("the server doesn't have a resource type '%s' in group '%s'\n", groupResource.Resource, groupResource.Group))
   333→				}
   334→			}
   335→			return schema.GroupVersionResource{Resource: resourceArg}
   336→		}
   337→	}
   338→
   339→	return gvr
   340→}
