   342→func (o *CanIOptions) printStatus(status authorizationv1.SubjectRulesReviewStatus) error {
   343→	if status.Incomplete {
   344→		o.WarningPrinter.Print(fmt.Sprintf("the list may be incomplete: %v", status.EvaluationError))
   345→	}
   346→
   347→	breakdownRules := []rbacv1.PolicyRule{}
   348→	for _, rule := range convertToPolicyRule(status) {
   349→		breakdownRules = append(breakdownRules, rbacutil.BreakdownRule(rule)...)
   350→	}
   351→
   352→	compactRules, err := rbacutil.CompactRules(breakdownRules)
   353→	if err != nil {
   354→		return err
   355→	}
   356→	sort.Stable(rbacutil.SortableRuleSlice(compactRules))
   357→
   358→	w := printers.GetNewTabWriter(o.Out)
   359→	defer w.Flush()
   360→
   361→	allErrs := []error{}
   362→	if !o.NoHeaders {
   363→		if err := printAccessHeaders(w); err != nil {
   364→			allErrs = append(allErrs, err)
   365→		}
   366→	}
   367→
   368→	if err := printAccess(w, compactRules); err != nil {
   369→		allErrs = append(allErrs, err)
   370→	}
   371→	return utilerrors.NewAggregate(allErrs)
   372→}
   373→
   374→func convertToPolicyRule(status authorizationv1.SubjectRulesReviewStatus) []rbacv1.PolicyRule {
   375→	ret := []rbacv1.PolicyRule{}
   376→	for _, resource := range status.ResourceRules {
   377→		ret = append(ret, rbacv1.PolicyRule{
   378→			Verbs:         resource.Verbs,
   379→			APIGroups:     resource.APIGroups,
   380→			Resources:     resource.Resources,
   381→			ResourceNames: resource.ResourceNames,
   382→		})
   383→	}
   384→
   385→	for _, nonResource := range status.NonResourceRules {
   386→		ret = append(ret, rbacv1.PolicyRule{
   387→			Verbs:           nonResource.Verbs,
   388→			NonResourceURLs: nonResource.NonResourceURLs,
   389→		})
   390→	}
   391→
   392→	return ret
   393→}
   394→
   395→func printAccessHeaders(out io.Writer) error {
   396→	columnNames := []string{"Resources", "Non-Resource URLs", "Resource Names", "Verbs"}
   397→	_, err := fmt.Fprintf(out, "%s\n", strings.Join(columnNames, "\t"))
   398→	return err
   399→}

